import scala.collection.mutable.PriorityQueue

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val nInt = n.toInt
  val outgoing = Array.ofDim[(Int, Long)](nInt)
  val incoming = Array.ofDim[(Int, Long)](nInt)

  for (edge <- edges) {
    val u = edge(0).toInt
    val v = edge(1).toInt
    val w = edge(2)
    outgoing(u) = outgoing(u) :+ (v, w)
    incoming(v) = incoming(v) :+ (u, w)
  }

  val dist = Array.ofDim[Long](nInt, 2)
  for (i <- 0 until nInt) {
    dist(i)(0) = Long.MaxValue
    dist(i)(1) = Long.MaxValue
  }
  dist(0)(0) = 0L

  val pq = PriorityQueue[(Long, Int, Int)]()
  pq.enqueue(0L, 0, 0)

  while (pq.nonEmpty) {
    val (cost, u, s) = pq.dequeue()
    if (u == nInt - 1) return cost
    if (cost > dist(u)(s)) continue

    for ((v, w) <- outgoing(u)) {
      val newCost = cost + w
      if (newCost < dist(v)(s)) {
        dist(v)(s) = newCost
        pq.enqueue(newCost, v, s)
      }
    }

    if (s == 0) {
      for ((source, w) <- incoming(u)) {
        val newCost = cost + 2 * w
        val newS = 1
        if (newCost < dist(source)(newS)) {
          dist(source)(newS) = newCost
          pq.enqueue(newCost, source, newS)
        }
      }
    }
  }

  -1L
}
